<template><div class="media-resources-container"><h2>Resource Generation</h2><p>AI-powered learning resource generator - images, charts, and courseware</p><el-alert v-if="!apiAvailable" title="API not configured, using local mode" type="info" show-icon :closable="false"></el-alert><el-tabs v-model="activeTab"><el-tab-pane label="Image" name="image"><el-form><el-form-item label="Description"><el-input type="textarea" v-model="imageForm.prompt" rows="4" placeholder="Describe the image you need..."></el-input><div class="prompt-templates"><el-tag v-for="t in promptTemplates" :key="t.label" size="small" @click="imageForm.prompt=t.value">{{t.label}}</el-tag></div></el-form-item><el-form-item><el-button type="primary" @click="generateImage" :loading="generating" :disabled="!imageForm.prompt">Generate</el-button></el-form-item></el-form><div class="preview-area"><img v-if="imageResult" :src="imageResult.url" style="max-width:100%;max-height:400px"></div></el-tab-pane><el-tab-pane label="Chart" name="chart"><el-form><el-form-item label="Chart Type"><el-select v-model="chartType"><el-option label="Bar" value="bar"></el-option><el-option label="Line" value="line"></el-option><el-option label="Pie" value="pie"></el-option></el-select></el-form-item><el-form-item label="Title"><el-input v-model="chartTitle"></el-input></el-form-item><el-form-item><el-button type="primary" @click="generateChart">Generate Chart</el-button></el-form-item></el-form><div class="preview-area"><v-chart v-if="chartOption" :option="chartOption" autoresize style="height:400px"></v-chart></div></el-tab-pane><el-tab-pane label="PPT" name="ppt"><resource-recommendation/></el-tab-pane></el-tabs></div></template><script>import axios from 'axios';import {use} from 'echarts/core';import {CanvasRenderer} from 'echarts/renderers';import {BarChart,LineChart,PieChart} from 'echarts/charts';import {TitleComponent,TooltipComponent,LegendComponent,GridComponent} from 'echarts/components';import VChart from 'vue-echarts';use([CanvasRenderer,BarChart,LineChart,PieChart,TitleComponent,TooltipComponent,LegendComponent,GridComponent]);export default{name:'MediaResourcesGenerator',components:{VChart,ResourceRecommendation:()=>import('./ResourceRecommendation.vue')},data(){return{activeTab:'image',generating:false,apiAvailable:false,imageForm:{prompt:'',style:'tech',size:'1024*1024',async:false},imageResult:null,chartType:'bar',chartTitle:'My Chart',chartOption:null,promptTemplates:[{label:'Course Cover',value:'University course cover, AI introduction, academic style, blue theme'},{label:'Knowledge Diagram',value:'Knowledge structure diagram, ML algorithms, infographic style'},{label:'Course Poster',value:'Course poster, Python programming, modern education tech style'}]}},created(){this.checkApi()},methods:{async checkApi(){try{const r=await axios.get('/api/image/status');this.apiAvailable=r.data&&r.data.configured===true}catch(e){this.apiAvailable=false}},async generateImage(){if(!this.imageForm.prompt)return;this.generating=true;try{const r=await axios.post('/api/image/generate',this.imageForm);if(r.data.task_status==='SUCCEEDED'&&r.data.results){this.imageResult=r.data.results[0];this.$message.success('Generated!')}else if(r.data.task_status==='FAILED'){this.$message.info('API unavailable, using local');this.generateLocal()}else{this.$message.error(r.data.message||'Failed')}}catch(e){this.$message.info('Using local generation');this.generateLocal()}this.generating=false},generateLocal(){const c=document.createElement('canvas');c.width=1024;c.height=1024;const ctx=c.getContext('2d');ctx.fillStyle='#1a2540';ctx.fillRect(0,0,1024,1024);ctx.fillStyle='#58a6ff';ctx.font='bold 40px sans-serif';ctx.textAlign='center';ctx.fillText(this.imageForm.prompt.slice(0,30),512,480);ctx.fillStyle='#8b949e';ctx.font='20px sans-serif';ctx.fillText('Qiongjing Cosmora',512,920);this.imageResult={url:c.toDataURL()}},generateChart(){this.chartOption={title:{text:this.chartTitle},tooltip:{},xAxis:{type:'category',data:['A','B','C']},yAxis:{type:'value'},series:[{type:this.chartType,data:[10,20,30]}]}}}}</script>